UPDATE animals SET gender=#{gender}, entry_date=#{entryDate}, breed=#{breed},
    batch_id=#{batchId}, current_pen_id=#{currentPenId}, birth_weight=#{birthWeight}
WHERE id = #{id}

mapper.select:
SELECT a.id, a.ear_tag, a.gender, DATE_FORMAT(a.entry_date,'%Y-%m-%d') as entry_date, a.breed, a.batch_id, a.current_pen_id, a.birth_weight, a.status, DATE_FORMAT(a.created_at,'%Y-%m-%d %H:%i:%s') as created_at, b.batch_code, p.pen_name as current_pen_name FROM animals a LEFT JOIN batches b ON a.batch_id = b.id LEFT JOIN pens p ON a.current_pen_id = p.id
(a.ear_tag LIKE CONCAT('%', #{search}, '%') OR a.breed LIKE CONCAT('%', #{search}, '%') OR b.batch_code LIKE CONCAT('%', #{search}, '%'))
AND a.status = #{status}
ORDER BY a.id LIMIT #{size} OFFSET #{offset}

